# OEIS sequence: A100778

from itertools import islice
from math import prod
from heapq import heappop, heappush
from sympy import factorint, nextprime
def A100778_gen(): # generator of terms if the first n terms are desired.
    h, hset = [1], {1}
    while True:
        yield (m:=heappop(h))
        ps = factorint(m)
        if m==1:
            heappush(h,2)
            hset.add(2)
        else:
            mp = m*prod(ps.keys())
            if mp not in hset:
                heappush(h,mp)
                hset.add(mp)
            mp = m*nextprime(p:=max(ps.keys()))**ps[p]
            if mp not in hset:
                heappush(h,mp)
                hset.add(mp)
A100778_list = list(islice(A100778_gen(),50)) # _Chai Wah Wu_, Mar 28 2026

